import{_ as e}from"./_plugin-vue_export-helper.cdc0426e.js";import{o,c,a as s,b as n,d as t,e as p,r as l}from"./app.14e74da6.js";const i={},u=p('<blockquote><p>Q：重构一个项目，要兼容 ie8，不能使用新语法。<br> A：为什么不能使用最新语法，即使需要兼容 ie8 也可以用现代开发的形式去兼容啊？<br> Q：你不用管那么多。还有，不能使用 CSS3 特性，一切 ie8 不支持的特性都不要使用。<br> A：？？？<br> A：这是怎么个事？要兼容 ie8 也有很多种方式啊，现在那么多 CSS 预处理器，而且很多 CSS3 特性是体验增强的，即使不支持也对用户没有影响。<br> Q：你话这么多还想不想干了，我有我自己的考虑。<br> A：。。。</p></blockquote><p>上述对话不是真实的，是我一个朋友最近的需求，Questions 是他对我阐述的领导需求，Answers 是我的想法，也是我想写这篇文章和大家探讨的原因。</p><p>从对话中可以看出需求是重构一个旧项目，但在前端生态蓬勃发展的今天仍使用旧的开发方式进行重构。就以我个人的想法而言，是觉得这种重构是无效且无益的；以我看过的很多政府或偏政府项目来说，忽略了占据更大比例的使用现代浏览器的用户，而以 ie 这种古早浏览器为主向上兼容，而不是以现代浏览器为主去向下兼容，个人觉得是非常不合理的。</p><p>当然在最近一次的面试中也和面试官聊了这个话题，他的回答感觉也是有一定道理的：</p><blockquote><p>以现代的方式来开发当然没错，但还要考虑其他因素，比如项目的开发周期和效率、开发人员对这个项目的熟悉度。</p></blockquote><p>感觉就是领导者和开发者的思维不同吧。</p><p>这篇文章也不是为了吐槽这种需求，而是讨论如何以现代开发的方式去兼容类似 ie8 这种古早浏览器。本人是没有相关经验的，所以提出的还是一些自己的想法来和大家探讨。</p><h2 id="语法兼容" tabindex="-1"><a class="header-anchor" href="#语法兼容" aria-hidden="true">#</a> 语法兼容</h2><p>像对话中说的，为了考虑 ie8 而禁止使用新语法，这是完全没有必要的。以 let、const 举例，如果我们禁止使用它而使用 var，那我们就不得不面对 var 缺失的块作用域以及变量提升所带来的烦恼；更何况还有更多有用的 js 新特性能够帮助我们大大得提升开发效率。</p>',9),r={href:"https://babeljs.io/",target:"_blank",rel:"noopener noreferrer"},k=s("code",null,"babel-loader",-1),d=s("code",null,"babel-plugin-transform-es3-*",-1),v=s("p",null,[s("img",{src:"http://qkc148.bvimg.com/18470/9aff0231bc3ead45.png",alt:"20230917154941",loading:"lazy"})],-1),b=s("h2",{id:"api-兼容",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#api-兼容","aria-hidden":"true"},"#"),n(" API 兼容")],-1),m=s("p",null,[n("即使能够兼容现有语法了，但仍不能说得上方便，我们平时还会经常使用一些新的 API 来完成项目开发，比如 "),s("code",null,"Promise"),n(" 以及数组的一些常用方法等，这些对于 ie 而言默认是不支持的，为此我们需要添加支持。")],-1),f={href:"https://babeljs.io/",target:"_blank",rel:"noopener noreferrer"},h=s("code",null,"babel-polyfill",-1),y=p(`<p><code>polyfill</code>，也就是腻子脚本，作用是填充不支持的功能。原理也很简单，对于一个不支持的功能，使用旧有特性进行模拟实现，比如：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">typeof</span> <span class="token class-name">Function</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span>call <span class="token operator">!==</span> <span class="token string">&#39;function&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token class-name">Function</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">call</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token function">call</span><span class="token punctuation">(</span><span class="token parameter">self</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    self<span class="token punctuation">.</span>__fn <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">;</span>
    <span class="token keyword">var</span> args <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
    <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">var</span> i <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> arguments<span class="token punctuation">.</span>length<span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      args<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span><span class="token string">&#39;arguments[&#39;</span> <span class="token operator">+</span> i <span class="token operator">+</span>  <span class="token string">&#39;]&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">var</span> callbackStr <span class="token operator">=</span> <span class="token string">&#39;self.__fn(&#39;</span> <span class="token operator">+</span> args<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span><span class="token string">&#39;,&#39;</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token string">&#39;)&#39;</span><span class="token punctuation">;</span>
    <span class="token keyword">var</span> result <span class="token operator">=</span> <span class="token function">eval</span><span class="token punctuation">(</span>callbackStr<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">delete</span> self<span class="token punctuation">.</span>__fn<span class="token punctuation">;</span>
    <span class="token keyword">return</span> result<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">typeof</span> <span class="token class-name">Array</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span>filter <span class="token operator">!==</span> <span class="token string">&#39;function&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token class-name">Array</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">filter</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token function">filter</span><span class="token punctuation">(</span><span class="token parameter">cb<span class="token punctuation">,</span> self</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">var</span> results <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
    <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">var</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token keyword">this</span><span class="token punctuation">.</span>length<span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">cb</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> <span class="token keyword">this</span><span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">,</span> i<span class="token punctuation">,</span> <span class="token keyword">this</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        results<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span> results<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样当对应的特性不存在时我们编写的代码依然能够正常工作，也不用考虑着这个 API 不支持那个特性不能使用了。</p><h2 id="抹平差异" tabindex="-1"><a class="header-anchor" href="#抹平差异" aria-hidden="true">#</a> 抹平差异</h2><p>除了一些语法与 API 外，其实一些特性在不同浏览器中都有对应的实现的，只是有些差异。比如目前常用的 <code>DOM2</code> 级别事件 <code>addEventListener</code> 在 ie 中可以通过 <code>attachEvent</code> 来实现类似功能，为此我们可以将两者封装为一个方法进行差异抹平：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>window<span class="token punctuation">.</span><span class="token function-variable function">_addEventListener</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token function">_addEventListener</span><span class="token punctuation">(</span><span class="token parameter">element<span class="token punctuation">,</span> type<span class="token punctuation">,</span> fn</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">function</span> <span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token parameter">element<span class="token punctuation">,</span> type<span class="token punctuation">,</span> fn</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> element<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span>type<span class="token punctuation">,</span> fn<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
  <span class="token keyword">function</span> <span class="token function">attachEvent</span><span class="token punctuation">(</span><span class="token parameter">element<span class="token punctuation">,</span> type<span class="token punctuation">,</span> fn</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> element<span class="token punctuation">.</span><span class="token function">attachEvent</span><span class="token punctuation">(</span><span class="token string">&#39;on&#39;</span> <span class="token operator">+</span> type<span class="token punctuation">,</span> fn<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
  <span class="token keyword">function</span> <span class="token function">on</span><span class="token punctuation">(</span><span class="token parameter">element<span class="token punctuation">,</span> type<span class="token punctuation">,</span> fn</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> element<span class="token punctuation">[</span><span class="token string">&#39;on&#39;</span> <span class="token operator">+</span> type<span class="token punctuation">]</span> <span class="token operator">=</span> fn<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>

  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">typeof</span> element<span class="token punctuation">.</span>addEventListener <span class="token operator">===</span> <span class="token string">&#39;function&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    window<span class="token punctuation">.</span>_addEventListener <span class="token operator">=</span> addEventListener<span class="token punctuation">;</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">typeof</span> element<span class="token punctuation">.</span>attachEvent <span class="token operator">===</span> <span class="token string">&#39;function&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    window<span class="token punctuation">.</span>_addEventListener <span class="token operator">=</span> attachEvent<span class="token punctuation">;</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    window<span class="token punctuation">.</span>_addEventListener <span class="token operator">=</span> on<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>

  <span class="token keyword">return</span> window<span class="token punctuation">.</span><span class="token function">_addEventListener</span><span class="token punctuation">(</span>element<span class="token punctuation">,</span> type<span class="token punctuation">,</span> fn<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>类似的还有 <code>ie</code> 中的事件对象，也可以封装一个 <code>getEvent(event)</code> 方法来抹平不同浏览器之间的差异化。</p><h2 id="css-特性" tabindex="-1"><a class="header-anchor" href="#css-特性" aria-hidden="true">#</a> CSS 特性</h2>`,8),_={href:"https://postcss.org/",target:"_blank",rel:"noopener noreferrer"},w={href:"https://yuanyxh.com/posts/css/css%20%E6%95%B0%E6%8D%AE%E7%B1%BB%E5%9E%8B%E4%B8%8E%E5%85%BC%E5%AE%B9%E5%A4%84%E7%90%86.html",target:"_blank",rel:"noopener noreferrer"},g=p('<p>关于 CSS 的兼容有很多插件可以做，这里也不想过多介绍，我想介绍的关于 CSS 体验增强特性。</p><h3 id="css-体验增强" tabindex="-1"><a class="header-anchor" href="#css-体验增强" aria-hidden="true">#</a> CSS 体验增强</h3><p>这个名词我是通过阅读 《CSS 新世界》 得知的，体验增强这个词很好理解，就是加强用户的体验，那么怎么做呢？</p><p>以一个弹窗为例子，你认为一个弹窗是直接渲染出现带来的体验好呢，还是淡入、淡出并伴随着上至下的位移出现体验好呢？这个问题的答案很明显，对于大部分用户而言，直接渲染出现带来的印象太突兀，但加入动画后这种感觉就会很大的减少，这就是动画带来的用户体验增强。</p><p><img src="http://qkc148.bvimg.com/18470/cc5731672913ddaf.gif" alt="w8iu2-rab6u" loading="lazy"></p><p>那么现在如果我们需要兼容 ie8，意味着我们必须放弃 CSS3 中的过渡和动画吗？</p><p>不，我们不需要放弃。对于 ie8 而言，即使它不支持 CSS3 过渡与动画，最大的可能也就是无法解析这两个 CSS 语句，对于程序的功能没有任何影响，但对于现代浏览器而言，它能带来的用户体验是非常高的，我们没有必要为了 ie8 而完全放弃这种体验增强特性。</p><p>还有更多的其他体验增强特性如 <code>CSS Scroll Snap</code>、<code>sroll-behavior</code> 等等，都是我们可以提升用户体验又不必担心兼容问题的特性，合理掌握并运用相信可以让我们的网站交互更上一层楼。</p><h2 id="结语" tabindex="-1"><a class="header-anchor" href="#结语" aria-hidden="true">#</a> 结语</h2><p>这篇文章就是我对于项目兼容的一些看法，当然是我以开发者视角来看待的，最终还是要结合实际来对项目进行规划，但不管怎么说一个 C 端项目还是希望以用户体验为主来考虑项目的设计。</p>',10),S={href:"https://github.com/xcatliu/react-ie8#cn-make-your-react-app-work-in-ie8",target:"_blank",rel:"noopener noreferrer"};function E(C,x){const a=l("ExternalLinkIcon");return o(),c("div",null,[u,s("p",null,[n("为此，我们可以使用 "),s("a",r,[n("babel"),t(a)]),n(" 的 "),k,n(" 和 "),d,n(" 来实现语法的兼容处理，即使是 ie8：")]),v,b,m,s("p",null,[n("我们可以使用 "),s("a",f,[n("babel"),t(a)]),n(" 的 "),h,n(" 来帮助我们填补这些功能的缺少。")]),y,s("p",null,[n("不光是 js，CSS3 的出现也带来了很多实用的功能。我们可以使用一些 CSS 预处理器来进行兼容处理，比如 "),s("a",_,[n("PostCSS"),t(a)]),n("。")]),s("p",null,[n("如果差异较大的话也可以参考我的另一篇文章 "),s("a",w,[n("CSS 数据类型与浏览器渐进兼容处理"),t(a)]),n(" 里说的，利用样式层叠的特性，将被指定浏览器接受的 css 样式放在前面，符合规范的 css 样式放在后面，这样部分浏览器能够识别前面的样式而忽略后面的，符合规范的浏览器则通过层叠特性覆盖前面的样式。")]),g,s("p",null,[n("写这篇文章的时候也查询了一些资料，发现了一个 react 兼容 ie8 的项目例子 "),s("a",S,[n("react-ie8"),t(a)]),n("，有需要或有兴趣的可以去看看。")])])}const j=e(i,[["render",E],["__file","compatible_discussion.html.vue"]]);export{j as default};
